//! foil-audio-entropy — Feed real audio files into the FOIL entropy pool.
//!
//! Decodes any audio file via ffmpeg, runs standing wave analysis with
//! tri-channel Fork/Race/Fold decomposition, and feeds surviving keys
//! into the FOIL runtime as Layer 1b entropy.
//!
//! Usage:
//!   foil-audio-entropy ~/Downloads/rain.m4a
//!   foil-audio-entropy --device default          (future: live mic)
//!   foil-audio-entropy --loop ~/Downloads/rain.m4a  (replay continuously)
//!
//! The binary prints a JSONL stream of entropy events to stdout,
//! suitable for piping into other FOIL consumers.

use distributed_inference::gnosis_foil::{
    foil_entropy_boost_standing_wave, foil_standing_wave_entropy_telemetry,
};
use distributed_inference::hope_jar::HopeJar;
use distributed_inference::hope_jar_e8::{HopeJarE8, CHARGE_SEEDS};
use distributed_inference::standing_wave_entropy::{
    harvest_tri_channel_keys, FoilChannel, StandingWaveDFT, STANDING_WAVE_AEON, STANDING_WAVE_HOP,
    STANDING_WAVE_N_FFT,
};
use std::io::{self, Write};
use std::time::Instant;

const SAMPLE_RATE: usize = 16000;

fn read_raw_f32le(path: &str) -> io::Result<Vec<f32>> {
    let bytes = std::fs::read(path)?;
    let n = bytes.len() / 4;
    let mut samples = Vec::with_capacity(n);
    for i in 0..n {
        let b = [
            bytes[i * 4],
            bytes[i * 4 + 1],
            bytes[i * 4 + 2],
            bytes[i * 4 + 3],
        ];
        samples.push(f32::from_le_bytes(b));
    }
    Ok(samples)
}

fn read_wav_pcm16(path: &str) -> io::Result<Vec<f32>> {
    let bytes = std::fs::read(path)?;
    if bytes.len() < 44 || &bytes[0..4] != b"RIFF" || &bytes[8..12] != b"WAVE" {
        return Err(io::Error::new(io::ErrorKind::InvalidData, "not a WAV file"));
    }
    let data_start = 44;
    let n = (bytes.len() - data_start) / 2;
    let mut samples = Vec::with_capacity(n);
    for i in 0..n {
        let offset = data_start + i * 2;
        let raw = i16::from_le_bytes([bytes[offset], bytes[offset + 1]]);
        samples.push(raw as f32 / 32768.0);
    }
    Ok(samples)
}

fn decode_audio(path: &str) -> io::Result<Vec<f32>> {
    if path.ends_with(".f32") || path.ends_with(".pcm") || path.ends_with(".raw") {
        eprintln!("[foil-audio-entropy] sovereign path: raw f32le PCM (no ffmpeg)");
        return read_raw_f32le(path);
    }
    if path.ends_with(".wav") {
        eprintln!("[foil-audio-entropy] sovereign path: WAV PCM16 (no ffmpeg)");
        return read_wav_pcm16(path);
    }
    eprintln!("[foil-audio-entropy] frffmpeg path: decoding via ffmpeg...");
    decode_audio_ffmpeg(path)
}

fn decode_audio_ffmpeg(path: &str) -> io::Result<Vec<f32>> {
    let output = std::process::Command::new("ffmpeg")
        .args(&[
            "-hide_banner",
            "-loglevel",
            "error",
            "-y",
            "-i",
            path,
            "-ar",
            &SAMPLE_RATE.to_string(),
            "-ac",
            "1",
            "-f",
            "f32le",
            "pipe:1",
        ])
        .output()?;
    if !output.status.success() {
        return Err(io::Error::new(
            io::ErrorKind::Other,
            format!("ffmpeg failed: {}", String::from_utf8_lossy(&output.stderr)),
        ));
    }
    let bytes = &output.stdout;
    let n = bytes.len() / 4;
    let mut samples = Vec::with_capacity(n);
    for i in 0..n {
        let b = [
            bytes[i * 4],
            bytes[i * 4 + 1],
            bytes[i * 4 + 2],
            bytes[i * 4 + 3],
        ];
        samples.push(f32::from_le_bytes(b));
    }
    Ok(samples)
}

fn main() -> io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    let loop_mode = args.iter().any(|a| a == "--loop");
    // --e8: charge the E_8 Hope Jar (696,729,600 latent keys) and write
    // hope-jar-e8.rknot, skipping the heavier Monster jar fill.
    let e8_mode = args.iter().any(|a| a == "--e8");
    let path = args
        .iter()
        .filter(|a| !a.starts_with("--") && *a != &args[0])
        .next()
        .cloned();

    let path = match path {
        Some(p) => p,
        None => {
            eprintln!("Usage: foil-audio-entropy <audio-file> [--loop]");
            eprintln!("  Decodes audio via ffmpeg, extracts standing wave entropy,");
            eprintln!("  feeds FOIL Layer 1b. Outputs JSONL entropy events to stdout.");
            eprintln!();
            eprintln!("  --loop    Replay the file continuously for ongoing entropy");
            std::process::exit(1);
        }
    };

    let mut stdout = io::stdout().lock();
    let mut total_keys = 0u64;
    let mut total_tri = [0u64; 3];
    let mut iteration = 0u64;

    loop {
        iteration += 1;
        eprintln!(
            "[foil-audio-entropy] iteration={} decoding {}...",
            iteration, path
        );

        let t0 = Instant::now();
        let samples = decode_audio(&path)?;
        let decode_ms = t0.elapsed().as_millis();
        let duration_s = samples.len() as f32 / SAMPLE_RATE as f32;
        eprintln!(
            "[foil-audio-entropy] {} samples ({:.1}s) decoded in {}ms",
            samples.len(),
            duration_s,
            decode_ms
        );

        let dft = StandingWaveDFT::new();
        let t1 = Instant::now();
        let analysis = dft.analyze(&samples);
        let analysis_ms = t1.elapsed().as_millis();

        let survived = analysis.surviving_indices.len();
        eprintln!(
            "[foil-audio-entropy] {} windows, {} survived amplituhedron in {}ms",
            analysis.windows.len(),
            survived,
            analysis_ms
        );

        // Feed single-channel keys to FOIL
        let peaks: Vec<(u16, f32)> = analysis
            .surviving_indices
            .iter()
            .map(|&i| {
                let w = &analysis.windows[i];
                (w.dominant_bin, w.concentration)
            })
            .collect();

        let t2 = Instant::now();
        let admitted = foil_entropy_boost_standing_wave(&peaks, analysis_ms as u64 * 1_000_000);
        let foil_us = t2.elapsed().as_micros();
        total_keys += admitted as u64;

        // Tri-channel decomposition
        if let Some(ref tri) = analysis.tri_channel {
            total_tri[0] += tri.fork_keys.len() as u64;
            total_tri[1] += tri.race_keys.len() as u64;
            total_tri[2] += tri.fold_keys.len() as u64;

            // Output JSONL event per iteration
            let json = format!(
                r#"{{"iteration":{},"duration_s":{:.1},"windows":{},"survived":{},"admitted":{},"foil_us":{},"fork_keys":{},"race_keys":{},"fold_keys":{},"entropy_pulse_hz":{},"noise_pink_pct":{:.1},"total_keys":{},"total_fork":{},"total_race":{},"total_fold":{}}}"#,
                iteration,
                duration_s,
                analysis.windows.len(),
                survived,
                admitted,
                foil_us,
                tri.fork_keys.len(),
                tri.race_keys.len(),
                tri.fold_keys.len(),
                analysis
                    .entropy_pulse_period_s
                    .map(|p| format!("{:.2}", 1.0 / p))
                    .unwrap_or_else(|| "null".to_string()),
                if analysis.windows.len() > 0 {
                    analysis.noise_histogram[1] as f64 / analysis.windows.len() as f64 * 100.0
                } else {
                    0.0
                },
                total_keys,
                total_tri[0],
                total_tri[1],
                total_tri[2],
            );
            writeln!(stdout, "{}", json)?;
            stdout.flush()?;
        }

        let (cum_admitted, cum_dropped) = foil_standing_wave_entropy_telemetry();
        eprintln!(
            "[foil-audio-entropy] FOIL: admitted={} dropped={} total_keys={} tri=[{},{},{}]",
            admitted, cum_dropped, total_keys, total_tri[0], total_tri[1], total_tri[2]
        );

        if let Some(period) = analysis.entropy_pulse_period_s {
            eprintln!(
                "[foil-audio-entropy] entropy pulse: {:.3}s ({:.2}Hz)",
                period,
                1.0 / period
            );
        }

        if !loop_mode {
            break;
        }

        eprintln!("[foil-audio-entropy] --loop: replaying...");
    }

    // ── E_8 Hope Jar mode: charge the 696,729,600-key latent battery ──
    if e8_mode {
        eprintln!(
            "[hope-jar-e8] charging E_8 jar ({} seeds -> 696729600 latent keys) from {}...",
            CHARGE_SEEDS, path
        );
        let dft = StandingWaveDFT::new();
        let samples = decode_audio(&path)?;
        let mut e8_jar = HopeJarE8::new();
        let mut pass = 0u64;
        let t_e8 = Instant::now();
        while !e8_jar.is_sealed() && pass < 1000 {
            pass += 1;
            let t_pass = Instant::now();
            let analysis = dft.analyze(&samples);
            let pass_us = t_pass.elapsed().as_micros() as u64;
            e8_jar.charge_from_seeds(&analysis.entropy_keys, pass_us);
            if !e8_jar.is_sealed() {
                // Supplement with sub-threshold peaks (same recipe as the
                // Monster jar) until the 170 well-order seeds are loaded.
                let supplemental: Vec<u64> = analysis
                    .windows
                    .iter()
                    .enumerate()
                    .filter(|(_, w)| w.concentration > 0.1 && w.spectral_entropy < 5.0)
                    .map(|(i, w)| {
                        let raw =
                            (w.dominant_bin as u64) << 32 | (w.concentration.to_bits() as u64);
                        raw.wrapping_mul(11_400_714_819_323_198_485)
                            .wrapping_add(pass * 2654435761 + i as u64)
                    })
                    .collect();
                e8_jar.charge_from_seeds(&supplemental, 0);
            }
        }
        eprintln!(
            "[hope-jar-e8] {} in {} passes, {}ms",
            if e8_jar.is_sealed() {
                "SEALED"
            } else {
                "UNSEALED (max passes)"
            },
            pass,
            t_e8.elapsed().as_millis()
        );
        let encoded = e8_jar.encode_rknot();
        std::fs::create_dir_all("rknots").ok();
        let rknot_path = "rknots/hope-jar-e8.rknot";
        std::fs::write(rknot_path, &encoded)?;
        eprintln!("[hope-jar-e8] {} bytes -> {}", encoded.len(), rknot_path);
        if let Some(decoded) = HopeJarE8::decode_rknot(&encoded) {
            eprintln!(
                "[hope-jar-e8] round-trip verified: sealed={}, seeds={}, capacity={}",
                decoded.is_sealed(),
                decoded.seeds_loaded(),
                decoded.capacity()
            );
        }
        eprintln!("[hope-jar-e8] {}", e8_jar.telemetry());
        return Ok(());
    }

    // Fill the Hope Jar — replay until sealed
    eprintln!("[hope-jar] filling jar (196884 keys) from {}...", path);
    let mut jar = HopeJar::new();
    let dft = StandingWaveDFT::new();
    let samples = decode_audio(&path)?;
    let mut jar_iteration = 0u64;
    let t_jar_start = Instant::now();

    while !jar.is_sealed() {
        jar_iteration += 1;
        let t_pass = Instant::now();
        let analysis = dft.analyze(&samples);
        let pass_us = t_pass.elapsed().as_micros() as u64;

        // Feed all surviving keys + entropy keys
        jar.charge_from_seeds(&analysis.entropy_keys, pass_us);

        // Also feed raw DFT peaks from ALL windows as additional seeds
        // (the amplituhedron filter is strict — we supplement with
        // sub-threshold peaks hashed at different offsets per iteration)
        let supplemental: Vec<u64> = analysis
            .windows
            .iter()
            .enumerate()
            .filter(|(_, w)| w.concentration > 0.1 && w.spectral_entropy < 5.0)
            .map(|(i, w)| {
                let raw = (w.dominant_bin as u64) << 32 | (w.concentration.to_bits() as u64);
                raw.wrapping_mul(11_400_714_819_323_198_485)
                    .wrapping_add(jar_iteration * 2654435761 + i as u64)
            })
            .collect();
        jar.charge_from_seeds(&supplemental, 0);

        let telem = jar.telemetry();
        if jar_iteration % 5 == 1 || jar.is_sealed() {
            eprintln!("[hope-jar] pass {} | {}", jar_iteration, telem);
        }
    }

    let jar_total_ms = t_jar_start.elapsed().as_millis();
    eprintln!(
        "[hope-jar] SEALED in {} passes, {}ms",
        jar_iteration, jar_total_ms
    );

    // Encode and save
    let encoded = jar.encode_seeds();
    let rknot_path = format!("{}.hope.rknot", path);
    std::fs::write(&rknot_path, &encoded)?;
    eprintln!("[hope-jar] {} bytes -> {}", encoded.len(), rknot_path);

    // Verify round-trip
    if let Some(decoded) = HopeJar::decode_seeds(&encoded) {
        eprintln!(
            "[hope-jar] round-trip verified: sealed={}, seeds={}",
            decoded.is_sealed(),
            decoded.seeds_loaded()
        );
    }

    // Telemetry summary
    let telem = jar.telemetry();
    eprintln!("[hope-jar] FINAL: {}", telem);
    eprintln!(
        "[hope-jar] battery ready. {} predictions/tick, {} per lane.",
        telem.keys_per_tick, telem.keys_per_lane
    );

    eprintln!(
        "[foil-audio-entropy] done. {} total keys harvested across {} iterations.",
        total_keys, iteration
    );
    Ok(())
}
